import{_ as d,o as a,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const l="/media/202409//1726642997.3067892.png",e="/media/202409//1726642997.311914.png",o="/media/202409//1726642997.3144994.png",n="/media/202409//1726642997.3234606.png",s="/media/202409//1726642997.3258848.png",p="/media/202409//1726642997.3280544.png",h="/media/202409//1726642997.3304355.png",m="/media/202409//1726642997.332463.png",c="/media/202409//1726642997.3375306.png",g="/media/202409//1726642997.3406572.png",u="/media/202409//1726642997.343713.png",b="/media/202409//1726642997.3473198.png",_="/media/202409//1726642997.3503077.png",f="/media/202409//1726642997.3537753.png",q="/media/202409//1726642997.356874.png",I="/media/202409//1726642997.3609314.png",k="/media/202409//1726642997.3646362.png",x="/media/202409//1726642997.3683512.png",A="/media/202409//1726642997.3729844.png",P="/media/202409//1726642997.3773947.png",y="/media/202409//1726642997.3810596.png",U="/media/202409//1726642997.385314.png",w="/media/202409//1726642997.3914196.png",S="/media/202409//1726642997.3954544.png",R="/media/202409//1726642997.398995.png",C=JSON.parse('{"title":"RK3588 多模态套件使用手册","description":"","frontmatter":{"title":"RK3588 多模态套件使用手册"},"headers":[],"relativePath":"hardware/rk3588-mm/manual.md","filePath":"hardware/rk3588-mm/manual.md","lastUpdated":null}'),B={name:"hardware/rk3588-mm/manual.md"};function D(v,t,T,z,E,K){return a(),r("div",null,[...t[0]||(t[0]=[i('<p><strong>目录</strong></p><ol><li>编写目的</li><li>包装清单及实体图</li><li>硬件接口描述</li><li>支持功能</li><li>使用指南 5.1. 准备工作 5.2. 使用模式 5.2.1. 作为输出语音交互指令从机模式 5.2.2. 作为输出语音交互指令从机模式 5.2.3. 作为AI工控机主机模式 5.3. 设备安装指导 5.3.1. 场景说明 5.3.2. 摄像头倾斜角度参考</li><li>接线指导</li><li>多模态软件体验</li><li>串口使用</li><li>3.5mm多模降噪音频输出</li><li>设备配网</li><li>AIUI接入</li><li>3588多模套件识别效果及效果优化</li><li>固件版本及升级</li><li>设备调试 14.1. 获取调试日志 14.2. 获取本地音频</li><li>常见问题</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3588s AIUI多模态套件开发资料（产品规格书、使用手册），可以点击下载: <a href="/media/attachment/2026/01/RK3588s_AIUI%E5%A4%9A%E6%A8%A1%E6%80%81%E5%A5%97%E4%BB%B6%E4%BA%A7%E5%93%81%E8%B5%84%E6%96%99.zip">【附件】RK3588s AIUI多模态套件产品资料.zip</a></p><h1 id="编写目的" tabindex="-1">编写目的 <a class="header-anchor" href="#编写目的" aria-label="Permalink to &quot;编写目的&quot;">​</a></h1><p>本文档旨在让用户快速体验RK3588多模态开发套件，以及快速根据项目不同需求进行效果验证。</p><h1 id="包装清单及实体图" tabindex="-1">包装清单及实体图 <a class="header-anchor" href="#包装清单及实体图" aria-label="Permalink to &quot;包装清单及实体图&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>类型</strong></td><td><strong>数量</strong></td></tr><tr><td>1</td><td>RK3588板卡</td><td>1 个</td></tr><tr><td>2</td><td>电源线</td><td>1个</td></tr><tr><td>3</td><td>麦克风（线性四麦）</td><td>1个</td></tr><tr><td>4</td><td>麦克风连接线</td><td>1根</td></tr><tr><td>5</td><td>摄像头（不支持调焦距）</td><td>1个</td></tr><tr><td>6</td><td>摄像头连接线</td><td>1根</td></tr><tr><td>7</td><td>3.5mm音频线（用于音频输出和外部回采接入）</td><td>2根</td></tr><tr><td>8</td><td>固定支架</td><td>2个</td></tr><tr><td>9</td><td>Type-C调试线</td><td>1根</td></tr><tr><td>10</td><td>Wifi信号线</td><td>2根</td></tr></tbody></table><p><img src="'+l+'" alt="" title="null"></p><p><img src="'+e+'" alt="" title="null"></p><h1 id="硬件接口描述" tabindex="-1">硬件接口描述 <a class="header-anchor" href="#硬件接口描述" aria-label="Permalink to &quot;硬件接口描述&quot;">​</a></h1><p><img src="'+o+'" alt="" title="null"></p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>LAN</td><td>网口</td><td>千M以太网</td></tr><tr><td>DC-12V</td><td>电源输入接口</td><td>DC12V3A、DC5.5-2.1</td></tr><tr><td>USB3.0/USB2.0</td><td>USB接口</td><td>USB3.0 * 2 、USB2.0 * 4</td></tr><tr><td>USB3.0/USB2.0接口之间</td><td>复位按键</td><td>外部插针按住上电进入刷机模式</td></tr><tr><td>Type-C</td><td>ADB/DP接口</td><td>Typec接口，设备调试</td></tr><tr><td>HDMI</td><td>HDMI接口</td><td>HDMI 2.1接口 * 1，可最高输出8K 60Hz，HDCP2.3</td></tr><tr><td>MicArray</td><td>麦克风接口</td><td>支持4~8路麦克风输入</td></tr><tr><td>REF</td><td>Line in口</td><td>外部回采输入</td></tr><tr><td>SPEAKER</td><td>喇叭口</td><td>连接8Ω5W *2喇叭输出 4pin 2.0mm、+ - - +</td></tr><tr><td>HPOUT</td><td>Line out口</td><td>多模态降噪音频输出</td></tr><tr><td>RS232</td><td>RS232</td><td>RS232*2，串口通讯，默认支持蓝色232，黑色232为预留口</td></tr></tbody></table><h1 id="支持功能" tabindex="-1">支持功能 <a class="header-anchor" href="#支持功能" aria-label="Permalink to &quot;支持功能&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>功能</strong></td><td><strong>特性</strong></td><td><strong>备注</strong></td></tr><tr><td>回声消除</td><td>回声消除-25dB</td><td>标配</td></tr><tr><td>多模态降噪</td><td>噪声抑制-10dB</td><td>标配</td></tr><tr><td>人脸唤醒</td><td>检测唇形，免语音唤醒，人脸检测准确率达 99.99%</td><td>标配</td></tr><tr><td>在线识别</td><td>支持中英文和方言识别</td><td>标配</td></tr><tr><td>语义理解</td><td>支持自定义技能，提供 100 多个官方技能</td><td>标配</td></tr><tr><td>语音合成</td><td>支持中英文和方言合成</td><td>标配</td></tr><tr><td>串口通信</td><td>支持串口发送指令给上位机</td><td>标配</td></tr><tr><td>多模态降噪音频输出</td><td>通过HPOUT口输出多模态降噪后音频给上位机使用</td><td>标配</td></tr><tr><td>视频输出</td><td>通过千兆网口输出视频内容给上位机使用</td><td>标配</td></tr><tr><td>大模型交互</td><td>可接入星火大模型，让交互更自然</td><td>选配功能</td></tr><tr><td>超拟人合成</td><td>可模拟人类的口语化现象、情感、停顿等细节信息</td><td>选配功能</td></tr><tr><td>语音服务私有化部署</td><td>保障企业信息安全</td><td>选配功能</td></tr></tbody></table><h1 id="使用指南" tabindex="-1">使用指南 <a class="header-anchor" href="#使用指南" aria-label="Permalink to &quot;使用指南&quot;">​</a></h1><h2 id="_5-1-准备工作" tabindex="-1">5.1. 准备工作 <a class="header-anchor" href="#_5-1-准备工作" aria-label="Permalink to &quot;5.1. 准备工作&quot;">​</a></h2><ul><li>RK3588 多模态开发套件</li><li>HDMI线、显示屏、回采线</li><li>鼠标</li><li>上位机，如电脑（操作系统 windows10，用于调试）</li></ul><h2 id="_5-2-使用模式" tabindex="-1">5.2. 使用模式 <a class="header-anchor" href="#_5-2-使用模式" aria-label="Permalink to &quot;5.2. 使用模式&quot;">​</a></h2><h3 id="_5-2-1-作为输出语音交互指令从机模式" tabindex="-1">5.2.1. 作为输出语音交互指令从机模式 <a class="header-anchor" href="#_5-2-1-作为输出语音交互指令从机模式" aria-label="Permalink to &quot;5.2.1. 作为输出语音交互指令从机模式&quot;">​</a></h3><p><img src="'+n+'" alt="" title="null"></p><h3 id="_5-2-2-作为输出语音交互指令从机模式" tabindex="-1">5.2.2. 作为输出语音交互指令从机模式 <a class="header-anchor" href="#_5-2-2-作为输出语音交互指令从机模式" aria-label="Permalink to &quot;5.2.2. 作为输出语音交互指令从机模式&quot;">​</a></h3><p><img src="'+s+'" alt="" title="null"></p><h3 id="_5-2-3-作为ai工控机主机模式" tabindex="-1">5.2.3. 作为AI工控机主机模式 <a class="header-anchor" href="#_5-2-3-作为ai工控机主机模式" aria-label="Permalink to &quot;5.2.3. 作为AI工控机主机模式&quot;">​</a></h3><p><img src="'+p+'" alt="" title="null"></p><h2 id="_5-3-设备安装指导" tabindex="-1">5.3. 设备安装指导 <a class="header-anchor" href="#_5-3-设备安装指导" aria-label="Permalink to &quot;5.3. 设备安装指导&quot;">​</a></h2><h3 id="_5-3-1-场景说明" tabindex="-1">5.3.1. 场景说明 <a class="header-anchor" href="#_5-3-1-场景说明" aria-label="Permalink to &quot;5.3.1. 场景说明&quot;">​</a></h3><p>大屏设备高度在1.6米<s>2.1米，建议在距离大屏1.5米</s>3米的位置进行语音交互。<strong>麦克风及摄像头水平方向安装</strong>，需要根据设备实际高度调整倾斜角度，且摄像头放在麦克风板的居中位置</p><p><img src="'+h+'" alt="" title="null"></p><p><img src="'+m+'" alt="" title="null"></p><h3 id="_5-3-2-摄像头倾斜角度参考" tabindex="-1">5.3.2. 摄像头倾斜角度参考 <a class="header-anchor" href="#_5-3-2-摄像头倾斜角度参考" aria-label="Permalink to &quot;5.3.2. 摄像头倾斜角度参考&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>基于目前摄像头垂直视场角24度计算</strong></td><td></td></tr><tr><td><strong>设备高度</strong></td><td><strong>摄像头倾斜角度</strong></td></tr><tr><td>1.6米</td><td>0°</td></tr><tr><td>1.7米</td><td>向下倾斜5度</td></tr><tr><td>1.8米</td><td>向下倾斜5度</td></tr><tr><td>1.9米</td><td>向下倾斜10度</td></tr><tr><td>2米</td><td>向下倾斜15度</td></tr><tr><td>2.1米</td><td>向下倾斜15度</td></tr></tbody></table><h1 id="接线指导" tabindex="-1">接线指导 <a class="header-anchor" href="#接线指导" aria-label="Permalink to &quot;接线指导&quot;">​</a></h1><p>按照图示，从右向左依次连接网线，电源线，摄像头线，HDMI线，音频线。麦克风拾音孔需要正对人嘴，切勿堵住。摄像头能拍到人脸，且摆放角度正常。注意：</p><ul><li>如果上位机需要喇叭播报，则需要使用一分二音频线将送个喇叭信号的接入3588的3.5mm ref口进行<strong>回声消除</strong></li><li>如果将设备当<strong>主机</strong>使用需要语音播报的话，则需要3588接入喇叭，目前AIUI通用语义版本固件默认使用AIUI平台云端语义后播报，与appid绑定，需要应用开启合成播报功能，AIUI大模型版本固件使用本地主动合成，无需开启语音合成功能。</li><li>目前默认使用外接ref作为外部回采输入，如果当主机使用则需更改为内部回采输入</li></ul><p>AIUI配置文件路径：/sdcard/AIUI/cfg/aiui.cfg</p><p><strong>外部回采配置：”channel_filter”:”8,0,3,11,4,12”</strong></p><p><strong>内部回采配置：”channel_filter”:”8,0,3,11,5,13”</strong></p><p><strong>8,0,3,11为声卡采集的四个麦克风通道顺序，后两路4,12和5,13分别为声卡采集的外部回采通道和内部回采通道</strong></p><p><img src="'+c+'" alt="" title="null"></p><p><img src="'+g+'" alt="" title="null"></p><p><img src="'+u+'" alt="" title="null"></p><p><img src="'+b+'" alt="" title="null"></p><p><img src="'+_+'" alt="" title="null"></p><p>如图，上位机为Windows电脑，3.5mm一分二分别输出信号给到3588-ref口和喇叭口（此处用耳机代替）</p><h1 id="多模态软件体验" tabindex="-1">多模态软件体验 <a class="header-anchor" href="#多模态软件体验" aria-label="Permalink to &quot;多模态软件体验&quot;">​</a></h1><p>第一步：按住鼠标左键上划到此界面，找到AIUIService_Jniver软件，打开图中红框的体验apk</p><p><img src="'+f+'" alt="" title="null"></p><p>第二步：鼠标点击图像转换后预览</p><p><img src="'+q+'" alt="" title="null"></p><p>第三步：进入体验界面，人脸框住时可开始交互，人脸框住为主说话人，只支持单人交互，如果人脸被框柱，但是嘴巴被挡住为窄波束拾音，兼容戴口罩使用场景</p><p>体验环境：麦克风和摄像头切勿遮挡</p><p><img src="'+I+'" alt="" title="null"></p><h1 id="串口使用" tabindex="-1">串口使用 <a class="header-anchor" href="#串口使用" aria-label="Permalink to &quot;串口使用&quot;">​</a></h1><p>可以通过RS232接口输出主机串口信息给上位机。上位机可以拿到RK3588输出的人脸唤醒和休眠事件、识别和语义结果，具体信息见3588串口通信协议手册：**&lt;/hardware/rk3588-mm/semantic-protocol</p><p><strong>上位机：Windows、安卓，购买串口线型号，集成解析</strong></p><p>**第一步：**按照图示接好主机电源，麦克风音频线，摄像头线，串口线（接RS232接口）；</p><p><img src="'+k+'" alt="" title="null"></p><p>**第二步：**串口线另一头连接上位机（可根据上位机接口选择USB口或RS232串口），上位机需要安装对应的驱动程序，提供了win10和win11驱动：<a href="https://www.yuque.com/iflyaiui/zzoolv/zdafgmfb5gxa9yws?singleDoc" target="_blank" rel="noreferrer">https://www.yuque.com/iflyaiui/zzoolv/zdafgmfb5gxa9yws?singleDoc#</a> 《3588自带串口线-Windows上位机驱动程序》</p><p><img src="'+x+'" alt="" title="null"></p><p>**第三步：**如果上位机需要语音播报，rk3588需要接入回采数据，接口为盒子背部ref 3.5mm口</p><p>**第四步：**打开开发包中的小草莓图标的AIUI串口调试工具，波特率选择115200</p><p>第五步：验证串口是否正常工作：</p><ul><li><strong>方式1：</strong></li></ul><p>语音识别、语义的交互信息会在控制台中输出出来。</p><p><img src="'+A+'" alt="" title="null"></p><ul><li><strong>方式2：</strong></li></ul><p>adb shell,</p><p>向串口输入一段数据，看看串口工具能不能收到</p><p>echo 78 78 78 78 78 78 0a &gt; /dev/ttysWK1</p><p>此时串口如果通路正常，串口工具控制台会输出对应的二进制</p><h1 id="_3-5mm多模降噪音频输出" tabindex="-1">3.5mm多模降噪音频输出 <a class="header-anchor" href="#_3-5mm多模降噪音频输出" aria-label="Permalink to &quot;3.5mm多模降噪音频输出&quot;">​</a></h1><p>如果上位机有自己的语音服务，需要RK3588主机输出降噪后音频，可通</p><p>过3.5mm音频线从HPOUT口输出音频给上位机，<strong>没有人脸时也输出音频，可结合RS232串口输出的人脸唤醒状态进行语音识别。</strong></p><p>**第一步：**按照图示接好主机电源，麦克风音频线，摄像头线（接USB2.0），3.5mm耳机线（接HPOUT口），串口线（接RS232口）；</p><p><img src="'+P+'" alt="" title="null"></p><p>**第二步：**3.5mm音频线另一端接入上位机，如果上位机为4段式3.5mm接口（例如笔记本电脑），需要另外装配一根耳麦二合一转接线，3.5mm接入到二合一线的麦克风口。</p><p><img src="'+y+'" alt="" title="null"></p><p>**第三步：**上位机通过对应的声卡进行录音</p><h1 id="设备配网" tabindex="-1">设备配网 <a class="header-anchor" href="#设备配网" aria-label="Permalink to &quot;设备配网&quot;">​</a></h1><p>1.支持dhcp，可以连接网线或通过串口进行wifi配置或可视化配网</p><p>2.不支持dhcp，可以通过串口设置静态ip</p><h1 id="aiui接入" tabindex="-1">AIUI接入 <a class="header-anchor" href="#aiui接入" aria-label="Permalink to &quot;AIUI接入&quot;">​</a></h1><p>真实项目使用需更换appid（可以自行配置云端技能，自定义技能、热词识别效果优化，AIUI开放平台官网入门指导：&lt;/platform-service/quickstart</p><p>1.将appid提供给讯飞，大模型版本需要额外授权且固件不同（AIUI平台语义理解配置处需勾选星火认知交互大模型），请联系讯飞商务申请多模态授权</p><p>需要注意默认可能不允许adb调试，需要进入接hdmi投屏后，进入盒子设置-》打开调试权限后adb进去</p><p>2.通过type-C接口连接电脑，安装adb工具，执行：</p><p>adb pull /sdcard/AIUI/cfg/aiui.cfg</p><p>修改aiui.cfg中的appid和key参数，对应AIUI平台</p><p>修改后上传，adb push aiui.cfg /sdcard/AIUI/cfg/</p><p>重启盒子生效，adb reboot</p><p><img src="'+U+'" alt="" title="null"></p><h1 id="_3588多模套件识别效果及效果优化" tabindex="-1">3588多模套件识别效果及效果优化 <a class="header-anchor" href="#_3588多模套件识别效果及效果优化" aria-label="Permalink to &quot;3588多模套件识别效果及效果优化&quot;">​</a></h1><ul><li><strong>识别准确率</strong> 在摄像头高度1.5-2.1米，人身高1.5-1.9米，人声和噪音信噪比为-5db，光照度300Lx场景下，不同距离的识别准确率如下：</li></ul><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>交互距离</strong></td><td><strong>1.5米~2米</strong></td><td><strong>2米~2.5米</strong></td><td><strong>2.5米~3米</strong></td></tr><tr><td>字准率</td><td>95%</td><td>93%</td><td>90%</td></tr></tbody></table><ul><li><strong>效果说明</strong><ul><li>识别效果与具体设备、场景强相关，在具体项目上的效果需要结合硬件质量评估，如：结构气密性、上位机回采信号质量、主机电路干扰等，如有问题可以申请讯飞技术支持协助排查</li><li>摄像头高度、距离等会影响测试数据波动</li><li>主交互人不能带口罩测试</li><li><strong>如有与业务相关的产品名、操作指令、地名、人名等需在AIUI平台应用中添加热词优化，如添加热词还无法识别正确则需要训练优化（需要成本，请联系项目经理）</strong></li></ul></li></ul><h1 id="固件版本及升级" tabindex="-1">固件版本及升级 <a class="header-anchor" href="#固件版本及升级" aria-label="Permalink to &quot;固件版本及升级&quot;">​</a></h1><p>目前分通用语义版本固件和交互大模型版本固件，采购前请与商务说明清楚，固件升级步骤如下：</p><p>第一步：盒子接Type-C调试线，另一端连接Windows电脑</p><p>第二步：卸载自带软件：双击uninstall.bat</p><p>第三步：安装软件：双击install.bat</p><h3 id="注意" tabindex="-1">注意： <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>固件获取请联系项目或技术支持同事，无特殊需求无需更新固件</p><p><img src="'+w+'" alt="" title="null"></p><h1 id="设备调试" tabindex="-1">设备调试 <a class="header-anchor" href="#设备调试" aria-label="Permalink to &quot;设备调试&quot;">​</a></h1><h2 id="_14-1-获取调试日志" tabindex="-1">14.1. 获取调试日志 <a class="header-anchor" href="#_14-1-获取调试日志" aria-label="Permalink to &quot;14.1. 获取调试日志&quot;">​</a></h2><p>安装adb工具：<a href="https://blog.csdn.net/Python_0011/article/details/132040387" target="_blank" rel="noreferrer">https://blog.csdn.net/Python_0011/article/details/132040387</a></p><p>当出现异常问题时，需要获取调试日志分析，重启盒子开机后，执行如下操作</p><p>1.打开cmd终端，执行adb logcat &gt; 123.txt</p><p>2.复现问题，等待10s</p><p>3.cmd终端执行ctrl+c 结束，日志生成在当前目录，把日志(123.txt)发回讯飞检查</p><h2 id="_14-2-获取本地音频" tabindex="-1">14.2. 获取本地音频 <a class="header-anchor" href="#_14-2-获取本地音频" aria-label="Permalink to &quot;14.2. 获取本地音频&quot;">​</a></h2><p>1）adb shell</p><p>2）修改配置文件</p><p>busybox vi /sdcard/AIUI/mmsp/cfg/mmsp.cfg</p><p>将save_datalog改为1</p><p>如果shell乱码，可以将配置文件导出到本地修改，然后push进去</p><p>3）重启设备</p><p>adb reboot</p><p>4）音频会存储在/sdcard/AIUI/mmsp/data目录下，每次交互会产生新的音频</p><p><img src="'+S+'" alt="" title="null"></p><p>5）将音频拉到本地</p><p>adb pull sdcard/AIUI/mmsp/data .</p><p>6）保存完音频后将save_datalog还原成0</p><p>然后adb reboot重启设备，不然可能导致机器存储满而导致卡死</p><p>7）音频说明：</p><p>可以将音频文件添加.pcm后缀名，使用Adobe_Audition打开查看</p><p>音频软件使用教程：<a href="https://www.yuque.com/iflyaiui/zzoolv/acykkh?singleDoc#" target="_blank" rel="noreferrer">https://www.yuque.com/iflyaiui/zzoolv/acykkh?singleDoc#</a> 《音频分析软件-Audition》</p><p><img src="'+R+'" alt="" title="null"></p><h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><table tabindex="0"><thead><tr><th>问题描述</th><th>解决办法</th></tr></thead><tbody><tr><td>设备能识别到人脸，但说话无识别内容</td><td>1、检查下设备是否具备网络，设置 — 高级设置 — dhcp — 查看网络的ip地址是否获取到了； 2、查看下设备的时间是否正确，时间若不正确，鉴权会失败，则无法交互。</td></tr><tr><td>摄像头黑屏</td><td>1、检查网络是否正常，打开浏览器访问外网 2、 打开系统相机是否正常，确保摄像头本身无问题</td></tr><tr><td>开启盒子调试模式后导致内存满了无法进入系统</td><td><strong>第一步</strong>：用Type_c链接上 使用adb命令 adb devices是否有识别。 <strong>第二步</strong>：若adb devices没有设备，则插入Type-c，重启盒子就会有adb链接。 <strong>第三步</strong>：有adb 链接后，adb shell进入盒子链接。 <strong>第四步</strong>：在adb shell中 输入df 看是不是data目录满载。也是存储100%了。 <strong>第五步</strong>：若data是100%储存了，则输入 /data/media/0/AIUI/mmsp/data。 <strong>第六步</strong>： cd到此目录下后 ls -ls查看是否具有很多 data137 dataxxx文件。 <strong>第七步</strong>：将这些文件全部删除。 <strong>第八步</strong>： 删除后cd 到 /data/media/0/AIUI/mmsp/cfg目录下。 <strong>第九步</strong>: 输入adb reboot 重启盒子即可</td></tr><tr><td>视频预览界面状态码</td><td>audio_state：0声卡打开，-1失败，-999未初始化状态 video_state: 0摄像头打开，-1失败，-999未初始化状态 engine_state：10010，未授权 多模态初始化状态，错误码参照文档 mic_test:音频写入过程状态码，参照文档</td></tr><tr><td>错误码信息在哪里查看</td><td><a href="https://www.yuque.com/iflyaiui/zzoolv/igbuol?singleDoc#" title="点击这里查看" target="_blank" rel="noreferrer">点击这里查看</a></td></tr><tr><td>摄像头安装反了，可以通过软件调整角度嘛？</td><td>可以，可以修改aiui.cfg中的字段”cam_rotate”:”0”修改角度，如旋转180度则改为”cam_rotate”:”180”，重启软件后生效。</td></tr></tbody></table>',131)])])}const M=d(B,[["render",D]]);export{C as __pageData,M as default};
